// ── MultiBlocProvider — clean structure for app shell ──
class AppShell extends StatelessWidget {
  const AppShell({super.key, required this.child});
  final Widget child;
  @override Widget build(BuildContext context) {
    return MultiBlocProvider(
      providers: [
        BlocProvider<AuthBloc>(
          lazy: false,                    // bootstrap auth before first frame
          create: (ctx) => AuthBloc(ctx.read<AuthRepository>())..add(const Bootstrap()),
        ),
        BlocProvider<ThemeCubit>(
          create: (_) => ThemeCubit(),
        ),
      ],
      child: child,
    );
  }
}

// ── BlocProvider.value — pass an existing bloc to a modal ──
IconButton(
  icon: const Icon(Icons.shopping_cart),
  onPressed: () {
    final cart = context.read<CartBloc>();
    showModalBottomSheet(
      context: context,
      builder: (_) => BlocProvider.value(
        value: cart,                       // ✅ same instance — modal sees existing items
        child: const CartSheet(),
      ),
    );
  },
);

// ── ❌ Anti-pattern: BlocProvider in a Navigator.push without forwarding ──
Navigator.of(context).push(MaterialPageRoute(
  builder: (_) => const NextScreen(),    // ❌ NextScreen tries to context.read<CartBloc>() — not found
));

// ✅ Forward the existing bloc
Navigator.of(context).push(MaterialPageRoute(
  builder: (_) => BlocProvider.value(
    value: context.read<CartBloc>(),
    child: const NextScreen(),
  ),
));

