// ── HydratedCubit — the simple case ──
class ThemeCubit extends HydratedCubit<ThemeMode> {
  ThemeCubit() : super(ThemeMode.system);

  void setMode(ThemeMode mode) => emit(mode);

  @override
  ThemeMode? fromJson(Map<String, dynamic> json) {
    final v = json['v'] as int?;
    if (v != 1) return null;                // unknown schema → fall back to initial
    return ThemeMode.values.byName(json['mode'] as String);
  }

  @override
  Map<String, dynamic>? toJson(ThemeMode state) => {
    'v': 1,
    'mode': state.name,
  };
}

// ── HydratedBloc with a complex state ──
@freezed
class DraftState with _\$DraftState {
  const factory DraftState({
    required String body,
    required DateTime updatedAt,
  }) = _Draft;
}

class DraftBloc extends HydratedBloc<DraftEvent, DraftState> {
  DraftBloc() : super(DraftState(body: '', updatedAt: DateTime.now())) {
    on<DraftEdited>((e, emit) =>
      emit(state.copyWith(body: e.text, updatedAt: DateTime.now())));
    on<DraftCleared>((_, emit) =>
      emit(DraftState(body: '', updatedAt: DateTime.now())));
  }

  @override
  DraftState? fromJson(Map<String, dynamic> json) {
    try {
      final v = json['v'] as int?;
      if (v != 1) return null;             // ✅ schema migration safety
      return DraftState(
        body: json['body'] as String,
        updatedAt: DateTime.parse(json['updatedAt'] as String),
      );
    } catch (e, s) {
      log('DraftBloc.fromJson: $e');
      return null;
    }
  }

  @override
  Map<String, dynamic>? toJson(DraftState s) => {
    'v': 1,
    'body': s.body,
    'updatedAt': s.updatedAt.toIso8601String(),
  };
}

