import 'package:bloc_test/bloc_test.dart';
import 'package:mocktail/mocktail.dart';
import 'package:flutter_test/flutter_test.dart';

class MockAuthRepo extends Mock implements AuthRepository {}

void main() {
  late MockAuthRepo repo;

  setUp(() {
    repo = MockAuthRepo();
    registerFallbackValue(const Bootstrap());
  });

  group('AuthBloc', () {
    blocTest<AuthBloc, AuthState>(
      'emits [Loading, Success] when login succeeds',
      setUp: () {
        when(() => repo.login('a@x.com', 'pwd'))
            .thenAnswer((_) async => User(id: 1, email: 'a@x.com'));
      },
      build: () => AuthBloc(repo),
      act: (bloc) => bloc.add(LoginRequested('a@x.com', 'pwd')),
      expect: () => [
        isA<AuthLoading>(),
        isA<AuthSuccess>().having((s) => s.user.email, 'email', 'a@x.com'),
      ],
      verify: (_) => verify(() => repo.login('a@x.com', 'pwd')).called(1),
    );

    blocTest<AuthBloc, AuthState>(
      'emits Failure on bad credentials',
      setUp: () {
        when(() => repo.login(any(), any())).thenThrow(const InvalidCredentials());
      },
      build: () => AuthBloc(repo),
      act: (bloc) => bloc.add(LoginRequested('a@x.com', 'wrong')),
      expect: () => [
        isA<AuthLoading>(),
        isA<AuthFailure>(),
      ],
    );

    blocTest<SearchBloc, SearchState>(
      'debounces and emits Loaded for the latest query',
      build: () => SearchBloc(FakeRepo()),
      act: (bloc) {
        bloc.add(QueryChanged('a'));
        bloc.add(QueryChanged('ab'));
        bloc.add(QueryChanged('abc'));        // only this should fire
      },
      wait: const Duration(milliseconds: 350),
      expect: () => [const Loading(), isA<Loaded>()],
    );
  });

  group('CounterCubit', () {
    blocTest<CounterCubit, int>(
      'emits [1, 2] when increment called twice',
      build: () => CounterCubit(),
      act: (c) { c.increment(); c.increment(); },
      expect: () => [1, 2],
    );

    blocTest<CounterCubit, int>(
      'seeds initial state for tests of mid-flow logic',
      build: () => CounterCubit(),
      seed: () => 10,
      act: (c) => c.increment(),
      expect: () => [11],
    );
  });
}

