@override
void onError(Object error, StackTrace stackTrace) {
  // Last-chance hook for this bloc
  log('FeedBloc error: $error');
  super.onError(error, stackTrace);       // ✅ forward to BlocObserver
}

// ── 4) Global BlocObserver — Crashlytics integration ──
class AppBlocObserver extends BlocObserver {
  @override
  void onError(BlocBase bloc, Object error, StackTrace stackTrace) {
    super.onError(bloc, error, stackTrace);
    FirebaseCrashlytics.instance.recordError(
      error, stackTrace,
      reason: 'bloc:${bloc.runtimeType}',
      information: ['state:${bloc.state}'],
    );
  }
}

void main() {
  Bloc.observer = AppBlocObserver();
  runApp(const App());
}

